FORWARD_CHAINING()
BEGIN
    SET working_memory = {known facts}
    SET agenda = {rules that can fire with working_memory}

    WHILE agenda is not empty DO
        SELECT rule from agenda

        IF all antecedents satisfied THEN
            // Fire the rule
            ADD consequent to working_memory
            ADD new facts to agenda

            // Explain which rule fired
            PRINT "Rule fired: " + rule.name
            PRINT "Added: " + rule.consequent
        END IF

        REMOVE rule from agenda
    END WHILE

    RETURN working_memory
END

