class WumpusAgent:
    def __init__(self, world_size=4):
        self.world_size = world_size
        self.position = (0, 0)  # Start at bottom-left
        self.orientation = 'East'
        self.visited = {(0, 0)}
        self.safe = {(0, 0)}
        self.possible_pits = set()
        self.possible_wumpus = set()
        self.has_gold = False
        self.cave = self.initialize_cave()

    def initialize_cave(self):
        # Initialize known safe squares
        return {
            (0, 0): {'safe': True, 'visited': True},
            (1, 0): {'safe': True, 'visited': False},
            (0, 1): {'safe': True, 'visited': False}
        }

    def process_percept(self, percept):
        """
        Process percept [stench, breeze, glitter, bump, scream]
        Update knowledge about the environment
        """
        stench, breeze, glitter, bump, scream = percept
        x, y = self.position

        # Update visited cells
        self.visited.add((x, y))

        # Update cave knowledge
        if (x, y) not in self.cave:
            self.cave[(x, y)] = {'safe': not breeze and not stench}

        # If breeze, adjacent cells might have pits
        if breeze:
            adjacent = self.get_adjacent_cells(x, y)
            for cell in adjacent:
                if cell not in self.visited:
                    self.possible_pits.add(cell)

        # If stench, adjacent cells might have wumpus
        if stench:
            adjacent = self.get_adjacent_cells(x, y)
            for cell in adjacent:
                if cell not in self.visited:
                    self.possible_wumpus.add(cell)

        # Handle glitter - gold is here!
        if glitter:
            self.has_gold = True
            print("Gold found!")

        return self.decide_action()

    def get_adjacent_cells(self, x, y):
        cells = []
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, y + dy
            if 0 <= nx < self.world_size and 0 <= ny < self.world_size:
                cells.append((nx, ny))
        return cells

    def decide_action(self):
        """
        Decide next action based on current knowledge
        Priority: Grab gold if glitter, otherwise explore safe unvisited cells
        """
        # Simple exploration strategy
        x, y = self.position

        # Try to move to safe, unvisited cell
        for cell in self.get_adjacent_cells(x, y):
            if cell in self.safe and cell not in self.visited:
                # Check if we can move safely
                if cell not in self.possible_pits and cell not in self.possible_wumpus:
                    return ('move', cell)

        return 'climb'  # Done exploring

# Example usage
